{"command": "cd /testbed && python -c "
import django
from django.conf import settings
settings.configure()
django.setup()

from decimal import Decimal
from django.template.defaultfilters import floatformat

print('Testing floatformat...')

# Test cases from the PR description
try:
    result = floatformat('0.00', 0)
    print(f'floatformat(\"0.00\", 0) = {result!r}')
except Exception as e:
    print(f'Error: {type(e).__name__}: {e}')

try:
    result = floatformat(Decimal('0.00'), 0)
    print(f'floatformat(Decimal(\"0.00\"), 0) = {result!r}')
except Exception as e:
    print(f'Error: {type(e).__name__}: {e}')

# Additional edge cases
print()
print('Additional edge cases:')
for val in ['0.000', '0.0000', '0', '0.0', '1.00', '1.0', '1', '0.01', '0.001', '-0.00', '100.00']:
    for p in [0, 1, -1, 2]:
        try:
            result = floatformat(val, p)
            print(f'  floatformat({val!r}, {p}) = {result!r}')
        except Exception as e:
            print(f'  floatformat({val!r}, {p}) = Error: {e}')
""}

